using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder — happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 25m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(45m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsCustomerId()
    {
        // Arrange
        var items = CreateItems(("Widget", 5m, 1));

        // Act
        var order = _service.CreateOrder("cust-42", items);

        // Assert
        Assert.AreEqual("cust-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_GeneratesNonEmptyId()
    {
        // Arrange
        var items = CreateItems(("Widget", 5m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToUtcNow()
    {
        // Arrange
        var items = CreateItems(("Widget", 5m, 1));
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsInRange(order.CreatedAt, before, after);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_CalculatesTotalFromPriceTimesQuantity()
    {
        // Arrange — 3×$10 + 2×$15 = $60
        var items = CreateItems(("A", 10m, 3), ("B", 15m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(60m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 5m, 1), ("Gadget", 10m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.HasCount(2, order.Items);
    }

    #endregion

    #region CreateOrder — validation / exceptions

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateItems(("Widget", 5m, 1));

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(() => _service.CreateOrder("cust-1", items));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var created = _service.CreateOrder("cust-1", CreateItems(("Widget", 5m, 1)));

        // Act
        var found = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        // Act
        var result = _service.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithMatchingOrders_ReturnsAllForCustomer()
    {
        // Arrange
        _service.CreateOrder("cust-A", CreateItems(("W1", 5m, 1)));
        _service.CreateOrder("cust-A", CreateItems(("W2", 10m, 1)));
        _service.CreateOrder("cust-B", CreateItems(("W3", 15m, 1)));

        // Act
        var orders = _service.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoMatchingOrders_ReturnsEmptyList()
    {
        // Arrange
        _service.CreateOrder("cust-A", CreateItems(("W1", 5m, 1)));

        // Act
        var orders = _service.GetOrdersByCustomer("cust-Z");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyOrdersForRequestedCustomer()
    {
        // Arrange
        _service.CreateOrder("cust-A", CreateItems(("Widget", 5m, 1)));
        var expected = _service.CreateOrder("cust-B", CreateItems(("Gadget", 10m, 1)));

        // Act
        var orders = _service.GetOrdersByCustomer("cust-B");

        // Assert
        var single = Assert.ContainsSingle(orders);
        Assert.AreEqual(expected.Id, single.Id);
    }

    #endregion
}

